#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
struct Edge
{
	int u, v, w;
	bool operator <(const Edge& x1)
	{
		return w < x1.w;
	}
} edge[100010];
int n, p, js, ans, minn = INT_MAX;
int sj[10010];
int fa[10010];
int find(int a)
{
	if (fa[a] != a)fa[a] = find(fa[a]);
	return fa[a];
}
int main(void)
{
	cin >> n >> p;
	for (int i = 1; i <= n; ++i)
	{
		fa[i] = i;
		cin >> sj[i];
		minn = min(sj[i], minn);
	}
	for (int i = 1; i <= p; ++i)
	{
		int u, v, w;
		cin >> u >> v >> w;
		edge[i] = {u, v, sj[u] + sj[v] + 2 * w};

	}
	sort(edge + 1, edge + 1 + p);
	for (int i = 1; js != n - 1; ++i)
	{
		int u = edge[i].u, v = edge[i].v, w = edge[i].w;
		if (find(u) == find(v))
		{
			continue;
		}
		fa[find(u)] = find(v);
		js++;
		ans += w;
	}
	cout << ans + minn;
	return false;
}
